/**
 * MedX breadcrumb runtime — runs on `npm run start` via medx-runtime-registry.cjs
 * Navigation trail for nested supply-chain views and detail drill-downs.
 */
const ROUTE_LABELS = Object.freeze({
  "/": "Dashboard",
  "/inventory": "Inventory",
  "/inventory/:sku": "Product detail",
  "/orders": "Orders",
  "/orders/:id": "Order detail",
  "/suppliers": "Suppliers",
  "/suppliers/:id": "Supplier profile",
  "/compliance": "Compliance",
  "/compliance/audits": "Audit log",
  "/settings": "Settings",
  "/settings/integrations": "Integrations",
});

const breadcrumbStacks = new Map();

function matchRouteLabel(path) {
  if (ROUTE_LABELS[path]) return ROUTE_LABELS[path];
  for (const [pattern, label] of Object.entries(ROUTE_LABELS)) {
    if (!pattern.includes(":")) continue;
    const regex = new RegExp("^" + pattern.replace(/:[^/]+/g, "[^/]+") + "$");
    if (regex.test(path)) return label;
  }
  return path.split("/").filter(Boolean).pop() ?? "Home";
}

function createBreadcrumbStack(id, paths) {
  const items = paths.map((path, index) => ({
    path,
    label: matchRouteLabel(path),
    isCurrent: index === paths.length - 1,
    href: path,
  }));
  const stack = { id, items, separator: "/", maxItems: 5 };
  breadcrumbStacks.set(id, stack);
  return stack;
}

function pushBreadcrumb(stackId, path) {
  const stack = breadcrumbStacks.get(stackId);
  if (!stack) return null;
  const existing = stack.items.findIndex((i) => i.path === path);
  if (existing >= 0) {
    stack.items = stack.items.slice(0, existing + 1);
    stack.items[existing].isCurrent = true;
    return stack;
  }
  for (const item of stack.items) item.isCurrent = false;
  stack.items.push({
    path,
    label: matchRouteLabel(path),
    isCurrent: true,
    href: path,
  });
  if (stack.items.length > stack.maxItems) {
    stack.items = [
      { path: "...", label: "...", isCurrent: false, href: null, ellipsis: true },
      ...stack.items.slice(-(stack.maxItems - 1)),
    ];
  }
  return stack;
}

function popBreadcrumb(stackId) {
  const stack = breadcrumbStacks.get(stackId);
  if (!stack || stack.items.length <= 1) return null;
  stack.items.pop();
  stack.items[stack.items.length - 1].isCurrent = true;
  return stack;
}

function getBreadcrumbJsonLd(stackId) {
  const stack = breadcrumbStacks.get(stackId);
  if (!stack) return null;
  return {
    "@context": "https://schema.org",
    "@type": "BreadcrumbList",
    itemListElement: stack.items
      .filter((i) => !i.ellipsis)
      .map((item, index) => ({
        "@type": "ListItem",
        position: index + 1,
        name: item.label,
        item: item.href,
      })),
  };
}

async function runMedxBreadcrumb() {
  console.log("[medx:ui:breadcrumb] runtime initialized");
  console.log(`[medx:ui:breadcrumb] routes=${Object.keys(ROUTE_LABELS).length}`);

  const nav = createBreadcrumbStack("main-nav", ["/", "/inventory"]);
  pushBreadcrumb("main-nav", "/inventory/SKU-1042");
  pushBreadcrumb("main-nav", "/orders");
  pushBreadcrumb("main-nav", "/orders/ORD-8842");
  pushBreadcrumb("main-nav", "/compliance");
  pushBreadcrumb("main-nav", "/compliance/audits");

  const jsonLd = getBreadcrumbJsonLd("main-nav");
  popBreadcrumb("main-nav");

  console.log(`[medx:ui:breadcrumb] stacks=${breadcrumbStacks.size}`);
  console.log("[medx:ui:breadcrumb] trail", nav.items.map((i) => i.label).join(" > "));
  console.log(`[medx:ui:breadcrumb] jsonLdItems=${jsonLd?.itemListElement?.length}`);
  console.log("[medx:ui:breadcrumb] bootstrap complete");
}

module.exports = runMedxBreadcrumb;
